        "privateGroup": true,
        "status": "active"
      },
      "notes": "Retrieving a group by existing ID should return the correct group."
    },
    {
      "name": "get_group_nonexistent_id",
      "input": "nonexistent-id-1234",
      "output": {
        "error": "Group not found"
      },
      "notes": "Retrieving a group by a nonexistent ID should return an error."
    },
    {
      "name": "update_group_valid",
      "input": {
        "id": "f325869a-ab0d-47b1-af28-4e117709ca71",
