      "output": {
        "id": "f325869a-ab0d-47b1-af28-4e117709ca71",
        "status": "inactive"
      },
      "notes": "Updating a group status should return the updated group."
    },
    {
      "name": "update_group_invalid_id",
      "input": {
        "id": "invalid-id",
        "status": "inactive"
      },
      "output": {
        "error": "Group not found"
      },
      "notes": "Updating a group with an invalid ID should return an error."
    },
